      function CF_amnt_analysisFormula return Char is

cursor cur_pen_account_rep is
select 
account_no, 
total_days, 
total_days_h, 
flg_kind, 
pen_class,
amnt1,
amnt2,
amnt1+amnt2 tot_amnt,
perc,
amnt3,
PERC_V
from pen_account_rep
where account_no=:p_acc_account_no;

v_cur_pen_account_rep  cur_pen_account_rep%rowtype;

my_total_days1  number;
my_total_days2  number;
my_total_days_h number;
my_text1				varchar2(1000);
my_text2				varchar2(1000);
my_text3				varchar2(1000);
my_text4				VARCHAR2(1000);

begin
	

	
open 	cur_pen_account_rep;
fetch cur_pen_account_rep
into  v_cur_pen_account_rep;
close cur_pen_account_rep;
                    
if v_cur_pen_account_rep.total_days<300 then                       
--my_total_days1	:=ceil(v_cur_pen_account_rep.total_days/300)*300;
my_total_days1	:=v_cur_pen_account_rep.total_days;
else
--my_total_days1	:=floor(v_cur_pen_account_rep.total_days/300)*300;
my_total_days1	:=v_cur_pen_account_rep.total_days;
end if;	
--my_total_days2	:=floor((v_cur_pen_account_rep.total_days-10500)/300)*300;
my_total_days2	:=v_cur_pen_account_rep.total_days-10500;
my_total_days_h	:=v_cur_pen_account_rep.total_days_h;



if v_cur_pen_account_rep.flg_kind='1' then
	 	my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||round(v_cur_pen_account_rep.pen_class,2)||' *  2% * ( '||my_total_days1||'/300 '||' ) '||' = '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
elsif v_cur_pen_account_rep.flg_kind='2' then
		my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||'0.02 * '||'10500/300* '||round(v_cur_pen_account_rep.pen_class,2)||' + '||'0.03* '||my_total_days2||'/300 '||'*'||round(v_cur_pen_account_rep.pen_class,2)||'='||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
else
		my_text1:='ΤO ΒΑΣΙΚΟ ΠΟΣΟ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ: '||round(v_cur_pen_account_rep.pen_class,2)||' *  2% * ( '||my_total_days1||'/300 '||' ) '||' = '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt1,2),'999G999G990D90'));
end if;

	
if v_cur_pen_account_rep.total_days_h<>0 AND NVL(v_cur_pen_account_rep.amnt2,0) > 0 then
	 my_text2:='TΟ ΠΟΣΟ ΤΗΣ ΠΡΟΣΑΥΞΗΣΗΣ ΒΑΡΕΩΝ ΑΝΑΛΥΕΤΑΙ ΩΣ ΕΞΗΣ : '||round(v_cur_pen_account_rep.pen_class,2)||'* 2% * 20% * ('||my_total_days_h||'/300) '||'='||Ltrim(to_char(round(v_cur_pen_account_rep.amnt2,2),'999G999G990D90'));
	 my_text1:=my_text1||chr(10)||my_text2;
 
	 IF	NVL(v_cur_pen_account_rep.amnt1,0) + NVL(v_cur_pen_account_rep.amnt2,0) != NVL(v_cur_pen_account_rep.amnt3,0) THEN

		my_text3:='ΤΟ ΣΥΝΟΛΙΚΟ Β.Π. ΜΕ ΤΗΝ ΑΥΞΗΣΗ ΤΟΥ ΕΤΟΥΣ ΑΙΤΗΣΗΣ ('||v_cur_pen_account_rep.perc_V||') ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt3,2),'999G999G990D90'));
		my_text1:=my_text1||chr(10)||my_text3;

   ELSE
		my_text3:='ΤΟ ΣΥΝΟΛΙΚΟ Β.Π. (ΔΕΝ ΕΧΕΙ ΔΟΘΕΙ ΑΥΞΗΣΗ ΤΟΥ ΕΤΟΥΣ ΑΙΤΗΣΗΣ) ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||LTRIM(TO_CHAR(ROUND(v_cur_pen_account_rep.amnt3,2),'999G999G990D90'));
		my_text1:=my_text1||CHR(10)||my_text3;   	

   END IF;

else

	 IF	NVL(v_cur_pen_account_rep.amnt1,0) + NVL(v_cur_pen_account_rep.amnt2,0) != NVL(v_cur_pen_account_rep.amnt3,0) THEN
		my_text3:='ΤΟ ΟΠΟΙΟ ΜΕ ΤΗΝ ΑΥΞΗΣΗ ΤΟΥ ΕΤΟΥΣ ΑΙΤΗΣΗΣ ('||v_cur_pen_account_rep.perc_V||') ΔΙΑΜΟΡΦΩΝΕΤΑΙ ΣΕ: '||Ltrim(to_char(round(v_cur_pen_account_rep.amnt3,2),'999G999G990D90'));
		my_text1:=my_text1||chr(10)||my_text3;
	 ELSE
		my_text3:='ΣΤΟ ΟΠΟΙΟ ΔΕΝ ΕΧΕΙ ΔΟΘΕΙ ΑΥΞΗΣΗ ΤΟΥ ΕΤΟΥΣ ΑΙΤΗΣΗΣ ';
		my_text1:=my_text1||CHR(10)||my_text3;	 	
	 END IF;

end if;


return my_text1;


  
end;

      function CF_12FORMULA0005 return Char is

v_percent NUMBER;
my_text1  VARCHAR2(50);
my_days								number;
v_boolean                       boolean;
V_Psycho		number;

begin
	
	select total_days
	into 		my_days  
	from 		pen_account_rep
	where account_no=:p_acc_account_no;
	

v_percent := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
                                         :P_DT_DECISION_YEAR,
                                         :P_DT_DEC_UNIT_CODE,
                                         :P_DEC_INCR_SEC_NO_SR, 
                                         '1',
			                                   0,
			                                   :p_form_id,
			                                   '00001',
			                                   '00035',
			                                   '00200');

	  	
		V_Psycho := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,
																						:P_DT_DECISION_YEAR,
																						:P_DT_DEC_UNIT_CODE,
																						:P_DEC_INCR_SEC_NO_SR,
																						'1',
	               				        						0,
	               				        						:p_form_id,
	               				        						'00001',
	               				        						'00035',
	               				        						'00261');

IF v_percent IS NULL
		OR (v_percent = 75 AND (my_days) >= 6000 AND (V_Psycho!='1' OR V_Psycho IS NULL) ) THEN
			v_percent := 100;
ELSIF (v_percent = 50 AND (my_days) >= 6000 AND (V_Psycho!='1' OR V_Psycho IS NULL) ) THEN
        v_percent := 75;
END IF;	               				        						

			                                   


if v_percent= 100 then
	 	my_text1:='ΜΕ ΠΟΣΟ ΙΣΟ ΜΕ ΤΗΣ ΠΛΗΡΟΥΣ ΣΥΝΤΑΞΗΣ';
elsif v_percent= 75 then
		my_text1:='ΜΕ ΠΟΣΟ ΙΣΟ ΜΕ ΤΟ 75% ΤΗΣ ΠΛΗΡΟΥΣ ΣΥΝΤΑΞΗΣ';
else
		my_text1:='ΜΕ ΠΟΣΟ ΙΣΟ ΜΕ ΤΟ 50% ΤΗΣ ΠΛΗΡΟΥΣ ΣΥΝΤΑΞΗΣ';
end if;

return my_text1;
  EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

