      function CF_soixeia_paymentsFormula return Char is

to_return varchar2(500);
v_iban      varchar2(60);

cursor Cur_Fact_Subtype_Existance IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='01069' AND 
pen_dec_fact_types_instance.ins_insured_id= :p_INSURED_ID AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND
pen_dec_fact_types_instance.dec_fact_type_code = '00111';
  
cursor Cur_Fact_Subtype_Existance_2 IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='01069' AND 
pen_dec_fact_types_instance.ins_insured_id= :p_INSURED_ID AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND
pen_dec_fact_types_instance.dec_fact_type_code = '00584';

V_DEATH_REASON VARCHAR2(20);
begin
    to_return :='';
    v_iban:=null;
       open Cur_Fact_Subtype_Existance;
     fetch Cur_Fact_Subtype_Existance into v_iban;
     close Cur_Fact_Subtype_Existance; 
     open Cur_Fact_Subtype_Existance_2;
     fetch Cur_Fact_Subtype_Existance_2 into V_DEATH_REASON;
     close Cur_Fact_Subtype_Existance_2;                                              
    if v_iban is not null then
        IF V_DEATH_REASON='1' THEN
            to_Return:='Πληρωμή Σύνταξης χωρίς πίστωση σε Τραπεζικό Λογαριασμό.';
        ELSE    
         to_Return:='Πληρωμή Σύνταξης με πίστωση σε Τραπεζικό Λογαριασμό.';
        END IF; 
    end if;
   return to_Return;
end;

      function CF_DEBT_DESCRFormula return Char is
TO_RETURN VARCHAR2(1000);

CURSOR C1 IS
 SELECT PRCN_DESCR
   FROM PPI_PEN_DEBTS_PRCN
  WHERE PRCN= :DEDUCTION_PENSION_FACTOR;
V_PRCN_DESCR VARCHAR2(200);  
begin
  if :debt_id='31' then
  	to_return:=:num_debt||'. Συμψηφίζεται '||:descr||' Συνολικού Ποσού: '||:TOTAL_DEDUCTION_AMMOUNT||' ΕΥΡΩ';
  else
  	OPEN C1;
  	FETCH C1 INTO V_PRCN_DESCR;
  	CLOSE C1;
  	to_return:='Παρακράτηση ';
  	if :DOSAGE_AMOUNT is not null then 
  			to_return:=:num_debt||'. '||to_return||' ποσού '||:DOSAGE_AMOUNT||' ΕΥΡΩ '||' της μηνιαίας Σύνταξης ';
  	else
  			to_return:=:num_debt||'. '||to_return||' ποσοστού '||V_PRCN_DESCR||' της μηνιαίας Σύνταξης ';
  	end if;		
  		to_return:=to_return||' για '||:descr||' από Συνολικό Ποσό: '||:TOTAL_DEDUCTION_AMMOUNT||' ΕΥΡΩ';
  end if;	
  return TO_RETURN;
end;

      function CF_DATESFormula return Char is
TO_RETURN VARCHAR2(1000);
CURSOR FETC_START_DATE IS
SELECT value 
  FROM pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code IN ('00025','00157') AND 
pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND
pen_dec_fact_types_instance.dec_fact_type_code IN ( '00040');

CURSOR FETC_END_DATE IS
SELECT value 
  FROM pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code IN ('00025','00157') AND 
pen_dec_fact_types_instance.ins_insured_id= :p_insured_id AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND
pen_dec_fact_types_instance.dec_fact_type_code IN ( '00041');

V_START_DATE DATE;
V_END_DATE DATE;
begin
	TO_RETURN:=:VALUE10;
	OPEN FETC_START_DATE;
	FETCH FETC_START_DATE INTO V_START_DATE;
	CLOSE FETC_START_DATE;
	
  OPEN FETC_END_DATE;
	FETCH FETC_END_DATE INTO V_END_DATE;
	CLOSE FETC_END_DATE;
	
	IF V_START_DATE IS NOT NULL AND V_END_DATE IS NOT NULL THEN
		TO_RETURN:=TO_RETURN||' Από '||V_START_DATE||' έως '|| V_end_DATE;
	end if;
	IF V_START_DATE IS NOT NULL AND V_END_DATE IS  NULL THEN
		TO_RETURN:=TO_RETURN||' Από '||V_START_DATE;
	end if;
	IF V_START_DATE IS  NULL AND V_END_DATE IS NOT NULL THEN
		TO_RETURN:=TO_RETURN||' Έως '|| V_end_DATE;
	end if;

	
  RETURN TO_RETURN;
end;

      function CF_EXIST_TEMPFormula return Number is
  cursor Find_temp_pension is
   select count(*)
		from pen_temp_decision_instance a
        where a.ins_insured_id= :P_INSURED_ID
          and a.status='1'
          and ((:product_code IN ('00001','00002' )  AND a.qc_per_prodinst_code IN ('1','9')  )
               OR  (:product_code NOT IN ('00001','00002' ) AND a.qc_per_prodinst_code=decode(:product_code, '00001','1','00002','9','3')))
          ; 
          --and a.qc_per_prodinst_code=decode(:product_CODE, '00001','1','00002','9','3');
 
 cursor Find_temp_pension_debt is
   select count(*)
		from pen_temp_decision_instance a
        where a.ins_insured_id= :P_INSURED_ID
          and a.status='1'
          and exists (  select '1' 
                        from PEN_TEMP_DEC_INSTANCE_DEBTS b
											WHERE b.STATUS='1'
											  AND DT_DEC_UNIT_CODE= a.DT_DEC_UNIT_CODE
											  AND  DT_DECISION_YEAR= a.DT_DECISION_YEAR
											  AND  DEC_INCR_SEQ_NO = a.DEC_INCR_SEQ_NO
											)               
          and a.qc_per_prodinst_code=decode(:product_CODE, '00001','1','00002','9','3');
           
v_temp_cnt number          ;
v_temp_debts_exist number;
v_desrc varchar2(500);
begin
  
  if :INSTITUTION_CODE in ('1','21000') then
		 	open Find_temp_pension;
		 	fetch Find_temp_pension into v_temp_cnt;
		 	close Find_temp_pension;		
			 if v_temp_cnt>0 then
			 	v_desrc:='Συμψηφίζονται ποσά Προσωρινής Σύνταξης';
			 	open Find_temp_pension_debt;
			 	fetch Find_temp_pension_debt into v_temp_debts_exist;
			 	close Find_temp_pension_debt;
			 	if v_temp_debts_exist>0 then
			 		v_desrc:=v_desrc||' και τυχόν υπόλοιπα οφειλών, θα παρακρατούνται από την παρούσα απόφαση'||'.';
			 	else
			 		v_desrc:=v_desrc||'.';
			 	end if;	
			 	:CP_EXIST_TEMP:=v_desrc;
			 END IF;		
  end if;
  
  RETURN 0;
end;

      function CF_work_end_dateFormula return Char is
to_return varchar2(500);
v_end_date      varchar2(60);

cursor Cur_Fact_Subtype_Existance IS 
  select distinct pen_dec_fact_types_instance.value
  from  pen_dec_fact_types_instance
WHERE pen_dec_fact_types_instance.title_code='00019' AND 
pen_dec_fact_types_instance.ins_insured_id= :p_INSURED_ID AND 
pen_dec_fact_types_instance.DI_DOCUMENT_TYPE_DEC_COCE_SR ='1'  AND 
pen_dec_fact_types_instance.DI_DEC_INCR_SEQ_NO_SR =  :P_DEC_INCR_SEC_NO_SR AND 
pen_dec_fact_types_instance.DI_DECISION_YEAR_SR = :p_dt_decision_year AND 
pen_dec_fact_types_instance.DI_DEC_UNIT_CODE_SR =  :p_dt_dec_unit_code AND
pen_dec_fact_types_instance.dec_fact_type_code = '00588';
  

begin
	to_return :='';
	v_end_date:=null;
	   open Cur_Fact_Subtype_Existance;
     fetch Cur_Fact_Subtype_Existance into v_end_date;
     close Cur_Fact_Subtype_Existance;                                              
    if v_end_date is not null then
    	 :CP_EXT_WRK_DATE:=1;
    	 to_Return:='ΗΜΕΡΟΜΗΝΙΑ ΔΙΑΚΟΠΗΣ ΕΡΓΑΣΙΑΣ:'||v_end_date;
    ELSE
    	:CP_EXT_WRK_DATE:=0;
    end if;
   return to_Return;
end;

